# Process data
credit_card_businesses = []
categories_dict = {}

for biz in businesses:
    attrs = biz.get('attributes', {})
    if not isinstance(attrs, dict):
        continue

    if attrs.get('BusinessAcceptsCreditCards') == 'True':
        biz_id = biz['business_id']
        desc = biz.get('description', '')

        # Extract categories
        cats = []

        # Pattern: services in ...
        m1 = re.search(r'services in (.+?)\.', desc)
        if m1:
            parts = re.split(r',\s*|\sand\s', m1.group(1))
            cats = [p.strip() for p in parts if p.strip()]

        # Pattern: including ...
        if not cats and 'including' in desc:
            m2 = re.search(r'including (.+?)\.', desc)
            if m2:
                parts = re.split(r',\s*|\sand\s', m2.group(1))
                cats = [p.strip() for p in parts if p.strip()]

        if not cats:
            cats = ['Uncategorized']

        credit_card_businesses.append({
            'id': biz_id,
            'ref': biz_id.replace('businessid_', 'businessref_'),
            'cats': cats
        })

        for cat in cats:
            categories_dict[cat] = categories_dict.get(cat, 0) + 1

# Find top category
